const GCAL_CALENDAR_ID = "coromisionerosdjesuscl@gmail.com";
const GCAL_API_KEY = "AIzaSyAFSJguKkIY1shCYA1HIFwv9OtaYGnu45k";

async function fetchGoogleCalendarEvents() {
  try {
    const now = new Date().toISOString();
    const calId = encodeURIComponent(GCAL_CALENDAR_ID);
    const url = `https://www.googleapis.com/calendar/v3/calendars/${calId}/events?key=${GCAL_API_KEY}&timeMin=${now}&maxResults=20&singleEvents=true&orderBy=startTime`;
    const res = await fetch(url, {
      signal: (() => {
        const c = new AbortController();
        setTimeout(() => c.abort(), 8000);
        return c.signal;
      })(),
    });
    if (!res.ok) return [];
    const data = await res.json();
    return (data.items || []).map((item) => {
      const start = item.start?.dateTime || item.start?.date || "";
      const isDateTime = !!item.start?.dateTime;
      const fecha = start.split("T")[0];
      const hora = isDateTime
        ? new Date(item.start.dateTime).toLocaleTimeString("es-CL", {
            hour: "2-digit",
            minute: "2-digit",
            hour12: false,
          })
        : "";
      const titulo = item.summary || "Sin título";
      const tl = titulo.toLowerCase();
      const tipo = tl.includes("ensayo")
        ? "ensayo"
        : tl.includes("misa") ||
          tl.includes("vigilia") ||
          tl.includes("corpus") ||
          tl.includes("pentecost") ||
          tl.includes("pascua")
        ? "misa"
        : "evento";
      return {
        id: item.id,
        titulo,
        fecha,
        hora,
        tipo,
        lugar: item.location || "",
        descripcion: item.description || "",
      };
    });
  } catch (e) {
    console.warn("Error cargando Google Calendar:", e);
    return [];
  }
}

// Token de sesión activo (se actualiza al hacer login)
let _authToken = null;
let _refreshToken = null;

async function refreshSession() {
  if (!_refreshToken) return false;
  try {
    const res = await fetch(
      `${SUPABASE_URL}/auth/v1/token?grant_type=refresh_token`,
      {
        method: "POST",
        headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
        body: JSON.stringify({ refresh_token: _refreshToken }),
      }
    );
    if (!res.ok) return false;
    const data = await res.json();
    _authToken = data.access_token;
    _refreshToken = data.refresh_token;
    // Persistir en localStorage para sobrevivir recargas
    localStorage.setItem("sb_access_token", data.access_token);
    localStorage.setItem("sb_refresh_token", data.refresh_token);
    return true;
  } catch {
    return false;
  }
}

// Intentar restaurar sesión desde localStorage al cargar
(function restoreSession() {
  const at = localStorage.getItem("sb_access_token");
  const rt = localStorage.getItem("sb_refresh_token");
  if (at) _authToken = at;
  if (rt) _refreshToken = rt;
})();

async function supabase(table, options = {}) {
  const {
    method = "GET",
    body,
    select = "*",
    filters = "",
    order = "",
  } = options;
  let url = `${SUPABASE_URL}/rest/v1/${table}?select=${select}${filters}${order}`;
  const makeHeaders = () => ({
    apikey: SUPABASE_KEY,
    Authorization: `Bearer ${_authToken || SUPABASE_KEY}`,
    "Content-Type": "application/json",
    Prefer: method === "POST" ? "return=representation" : "",
  });
  let res = await fetch(url, {
    method,
    headers: makeHeaders(),
    body: body ? JSON.stringify(body) : undefined,
  });
  // Si JWT expiró, intentar renovar y reintentar una vez
  if (res.status === 401) {
    const refreshed = await refreshSession();
    if (refreshed) {
      res = await fetch(url, {
        method,
        headers: makeHeaders(),
        body: body ? JSON.stringify(body) : undefined,
      });
    }
  }
  if (!res.ok) throw new Error(await res.text());
  return res.status === 204 ? null : res.json();
}

// Renovar token automáticamente cada 50 minutos (expira en 1 hora)
setInterval(() => {
  if (_refreshToken) refreshSession();
}, 50 * 60 * 1000);
async function authSignUp(email, password, nombre, cuerda, cumpleanos, genero) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/signup`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, password, data: { nombre, cuerda } }),
  });
  const data = await res.json();
  if (!res.ok)
    throw new Error(data.msg || data.message || "Error al registrar");
  if (!data.access_token)
    throw new Error(
      "Cuenta creada. Revisa tu correo para confirmarla antes de ingresar."
    );
  _authToken = data.access_token;
  _refreshToken = data.refresh_token;
  localStorage.setItem("sb_access_token", data.access_token);
  localStorage.setItem("sb_refresh_token", data.refresh_token);
  const uid = data.user?.id;
  // cuerda ya viene calculada (Soprano/Contralto/Tenor/Bajo/Admin)
  await fetch(`${SUPABASE_URL}/rest/v1/integrantes`, {
    method: "POST",
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${_authToken}`,
      "Content-Type": "application/json",
      Prefer: "return=representation",
    },
    body: JSON.stringify({
      nombre,
      email,
      cuerda: cuerda || "Soprano",
      cumpleanos: cumpleanos || "",
      genero: genero || "",
      auth_id: uid,
    }),
  });
  return data;
}

async function authSignIn(email, password) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, password }),
  });
  const data = await res.json();
  if (!res.ok)
    throw new Error(
      data.error_description || data.msg || "Credenciales incorrectas"
    );
  _authToken = data.access_token;
  _refreshToken = data.refresh_token;
  localStorage.setItem("sb_access_token", data.access_token);
  localStorage.setItem("sb_refresh_token", data.refresh_token);
  return data;
}

async function authResetPassword(email) {
  const redirectTo = "https://portal-coro-mj.vercel.app/?type=recovery";
  const res = await fetch(`${SUPABASE_URL}/auth/v1/recover`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
    body: JSON.stringify({ email, gotrue_meta_security: {}, redirect_to: redirectTo }),
  });
  if (!res.ok) {
    const d = await res.json();
    throw new Error(d.msg || "Error");
  }
}

async function authUpdatePassword(newPassword) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/user`, {
    method: "PUT",
    headers: {
      apikey: SUPABASE_KEY,
      "Content-Type": "application/json",
      Authorization: `Bearer ${_authToken}`,
    },
    body: JSON.stringify({ password: newPassword }),
  });
  if (!res.ok) {
    const d = await res.json();
    throw new Error(d.msg || "Error al actualizar contraseña");
  }
}

async function authSignOut() {
  if (!_authToken) return;
  await fetch(`${SUPABASE_URL}/auth/v1/logout`, {
    method: "POST",
    headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${_authToken}` },
  });
  _authToken = null;
  _refreshToken = null;
  localStorage.removeItem("sb_access_token");
  localStorage.removeItem("sb_refresh_token");
}

