  // ── Evangelio del próximo domingo ────────────────────────
  async function fetchEvangelioDominical(today) {
    const dow = today.getDay();
    const daysUntilSunday = dow === 0 ? 0 : 7 - dow;
    const domingo = new Date(today);
    domingo.setDate(today.getDate() + daysUntilSunday);
    const domingoStr = domingo.toLocaleDateString("es-CL", {
      weekday: "long",
      day: "numeric",
      month: "long",
      year: "numeric",
    });
    const domingoISO = domingo.toISOString().split("T")[0];

    try {
      const controller = new AbortController();
      const timer = setTimeout(() => controller.abort(), 25000);
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        signal: controller.signal,
        headers: {
          "Content-Type": "application/json",
          "anthropic-version": "2023-06-01",
          "anthropic-dangerous-direct-browser-access": "true",
        },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 2000,
          tools: [{ type: "web_search_20250305", name: "web_search" }],
          messages: [
            {
              role: "user",
              content: `Busca en internet el evangelio oficial de la misa dominical del ${domingoStr} (${domingoISO}) según el calendario litúrgico romano. Busca en evangelio.es, vaticano.va o catholic.net. Responde SOLO con JSON puro sin markdown:\n{"referencia":"Ej: Jn 15,9-17","texto":"texto completo del evangelio sin recortar","reflexion":"reflexión de 3 a 4 líneas para un coro de música sacra con aplicación al canto litúrgico","oracion":"oración breve de 2 líneas para rezar antes de ensayar","domingo":"nombre de la celebración litúrgica","fuente":"nombre del sitio web"}`,
            },
          ],
        }),
      });
      clearTimeout(timer);
      if (!res.ok) throw new Error("API error");
      const d = await res.json();
      const raw = (d.content || [])
        .filter((i) => i.type === "text")
        .map((i) => i.text || "")
        .join("")
        .replace(/```json|```/g, "")
        .trim();
      const jsonMatch = raw.match(/\{[\s\S]*?\}/);
      if (!jsonMatch) throw new Error("No JSON");
      const parsed = JSON.parse(jsonMatch[0]);
      if (!parsed.referencia || !parsed.texto)
        throw new Error("Datos incompletos");
      return parsed;
    } catch (e) {
      console.warn("Evangelio API error:", e.message);
      // Fallback con datos reales del domingo actual
      const EVANGELIOS = {
        // Semana de Pentecostés 2026
        "2026-05-24": {
          referencia: "Jn 20,19-23",
          texto:
            "Al atardecer de aquel día, el primero de la semana, estando cerradas las puertas del lugar donde se encontraban los discípulos por miedo a los judíos, llegó Jesús, se puso en medio y les dijo: «La paz sea con vosotros.» Dicho esto, les mostró las manos y el costado. Los discípulos se llenaron de alegría al ver al Señor. De nuevo les dijo: «La paz sea con vosotros. Como el Padre me envió, también yo os envío.» Después de decir esto, sopló sobre ellos y les dijo: «Recibid el Espíritu Santo; a quienes les perdonéis los pecados, les quedan perdonados.»",
          reflexion:
            "El Espíritu Santo nos anima a cantar con gozo y a ser instrumentos de paz en la liturgia.",
          oracion:
            "Ven, Espíritu Santo, llena nuestras voces de tu fuego y que nuestro canto sea ofrenda digna de tu gloria.",
          domingo: "Pentecostés",
          fuente: "Calendario litúrgico 2026",
        },
        "2026-05-31": {
          referencia: "Lc 7,11-17",
          texto:
            "Jesús se dirigió a una ciudad llamada Naín, e iban con él sus discípulos y mucha gente. Cuando se acercaba a la puerta de la ciudad, resultó que sacaban a enterrar a un muerto, hijo único de su madre, que era viuda. La ciudad acompañaba a la madre. Al verla el Señor, le dio lástima y le dijo: «No llores.» Se acercó y tocó el féretro; los que lo llevaban se detuvieron. Y dijo: «Joven, yo te lo mando: levántate.» El muerto se incorporó y empezó a hablar. Y Jesús se lo entregó a su madre.",
          reflexion:
            "Nuestra música proclama la vida que Cristo devuelve y el consuelo que el Señor ofrece a los afligidos.",
          oracion:
            "Señor, que nuestras voces eleven a los caídos y tu misericordia se haga presente hoy en este ensayo.",
          domingo: "X Domingo del Tiempo Ordinario",
          fuente: "Calendario litúrgico 2026",
        },
      };
      return (
        EVANGELIOS[domingoISO] || {
          referencia: "Jn 15,9-17",
          texto:
            "Como el Padre me amó, yo también os he amado. Permaneced en mi amor. Si guardáis mis mandamientos, permaneceréis en mi amor, lo mismo que yo he guardado los mandamientos de mi Padre y permanezco en su amor. Os he dicho esto para que mi alegría esté en vosotros y vuestra alegría llegue a plenitud.",
          reflexion:
            "Que nuestra música sea expresión del amor que permanece y de la alegría del Evangelio.",
          oracion:
            "Señor, que nuestro canto brote del amor que tú nos tienes y que tu alegría se haga presente en cada nota.",
          domingo: "Domingo del Tiempo Ordinario",
          fuente: "Evangelio según San Juan",
        }
      );
    }
  }

  async function fetchNoticiasCatolicas() {
    try {
      const res = await fetch(`${SUPABASE_URL}/functions/v1/noticias-rss`, {
        signal: AbortSignal.timeout(15000),
      });
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      if (Array.isArray(data) && data.length) {
        return data.map((n, i) => ({
          id: String(i),
          titulo: n.titulo || "Sin título",
          url: n.url || "https://www.vaticannews.va/es.html",
          fuente: n.fuente || "Vatican News",
        }));
      }
    } catch (e) {
      console.warn("Noticias fetch error:", e.message);
    }
    return [];
  }

  async function fetchDaily() {
    setAiLoading(true);
    fetchClima();

    // Noticias fallback inmediatas (se reemplazan si la API responde)
    const FALLBACK_NOTICIAS = [
      {
        id: "f0",
        titulo: "Últimas noticias del Papa y la Iglesia Universal",
        url: "https://www.vaticannews.va/es.html",
        fuente: "Vatican News",
      },
      {
        id: "f1",
        titulo: "Iglesia en el mundo: noticias de hoy",
        url: "https://www.vaticannews.va/es/iglesia.html",
        fuente: "Vatican News",
      },
      {
        id: "f2",
        titulo: "Documentos y enseñanzas del Magisterio",
        url: "https://www.vaticannews.va/es/vaticano.html",
        fuente: "Vatican News",
      },
    ];
    setNoticias(FALLBACK_NOTICIAS);

    // Intenta cargar noticias reales del día
    setNoticiasLoading(true);
    fetchNoticiasCatolicas()
      .then((data) => {
        if (data?.length > 0) setNoticias(data);
        setNoticiasLoading(false);
      })
      .catch(() => setNoticiasLoading(false));
    try {
      const today = new Date();
      const [santoralData, evangelioData] = await Promise.all([
        fetchSantoral(today),
        fetchEvangelioDominical(today),
      ]);
      setSantoral(santoralData || "Santos del día");
      setEvangelio(evangelioData);
    } catch {
      setSantoral("Santos del día");
      setEvangelio({
        referencia: "Jn 20,19-23",
        texto:
          "Al atardecer de aquel día, el primero de la semana, llegó Jesús, se puso en medio y les dijo: «La paz sea con vosotros.» Dicho esto, les mostró las manos y el costado. Los discípulos se llenaron de alegría al ver al Señor.",
        reflexion:
          "El Espíritu Santo nos anima a cantar con gozo y a ser instrumentos de paz en la liturgia.",
        oracion:
          "Ven, Espíritu Santo, llena nuestras voces de tu fuego y que nuestro canto sea ofrenda digna de tu gloria.",
        domingo: "Pentecostés",
        fuente: "Calendario litúrgico 2026",
      });
    }
    setAiLoading(false);
  }

  async function handleSignIn(email, password) {
    const data = await authSignIn(email, password);
    const perfil = await supabase("integrantes", {
      filters: `&email=eq.${encodeURIComponent(email)}`,
    });
    let p = perfil && perfil[0] ? perfil[0] : null;
    // Si no existe en integrantes (confirmó email pero el INSERT del signup falló), crearlo ahora
    if (!p) {
      const uid = data.user?.id;
      const nombre = data.user?.user_metadata?.nombre || email.split("@")[0];
      const cuerda = data.user?.user_metadata?.cuerda || "Soprano";
      try {
        await fetch(`${SUPABASE_URL}/rest/v1/integrantes`, {
          method: "POST",
          headers: {
            apikey: SUPABASE_KEY,
            Authorization: `Bearer ${data.access_token}`,
            "Content-Type": "application/json",
            Prefer: "return=representation",
          },
          body: JSON.stringify({ nombre, email, cuerda, auth_id: uid }),
        });
        const perfil2 = await supabase("integrantes", {
          filters: `&email=eq.${encodeURIComponent(email)}`,
        });
        p = perfil2 && perfil2[0] ? perfil2[0] : { nombre, email, cuerda };
      } catch (e) {
        p = { nombre, email, cuerda };
      }
    }
    setAuthToken(data.access_token);
    setUser(p);
    setView("app");
    registrarVisita(p, data.access_token);
    // Mostrar modal solo si no tiene permiso aún y no es usuario Visita
    setTimeout(() => {
      if (Notification.permission !== "granted" && !esVisita(p)) setShowPushModal(true);
    }, 2500);
  }

  async function handleSignUp(
    email,
    password,
    nombre,
    cuerda,
    cumpleanos,
    adminCode,
    genero
  ) {
    // Si el código secreto es correcto, registrar como Admin
    const finalCuerda =
      adminCode.trim() === SECRET_ADMIN_CODE ? "Admin" : cuerda;
    const data = await authSignUp(
      email,
      password,
      nombre,
      finalCuerda,
      cumpleanos,
      genero
    );
    const perfil = await supabase("integrantes", {
      filters: `&email=eq.${encodeURIComponent(email)}`,
    });
    const p =
      perfil && perfil[0] ? perfil[0] : { nombre, email, cuerda: finalCuerda };
    setAuthToken(data.access_token);
    setUser(p);
    setView("app");
    registrarVisita(p, data.access_token);
    // Mostrar modal solo si no tiene permiso aún y no es usuario Visita
    setTimeout(() => {
      if (Notification.permission !== "granted" && !esVisita(p)) setShowPushModal(true);
    }, 2500);
  }

  async function handleSignOut() {
    // Marcar offline antes de cerrar sesión
    if (user?.id) {
      try {
        await fetch(`${SUPABASE_URL}/rest/v1/presencia_online?integrante_id=eq.${user.id}`, {
          method: "PATCH",
          headers: {
            apikey: SUPABASE_KEY,
            Authorization: `Bearer ${_authToken || SUPABASE_KEY}`,
            "Content-Type": "application/json",
            Prefer: "return=minimal",
          },
          body: JSON.stringify({ ultimo_ping: new Date(0).toISOString() }),
        });
      } catch (e) { /* silencioso */ }
    }
    await authSignOut();
    setUser(null);
    setAuthToken(null);
    setView("login");
  }

