//  YOUTUBE WIDGET
// ══════════════════════════════════════════
const YOUTUBE_CHANNEL_ID = "UCmyLPDfcxu4VMTMztDnzdWA";

function YoutubeWidget({ compact = false }) {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [apiError, setApiError] = useState(false);
  const YOUTUBE_API_KEY = GCAL_API_KEY;

  useEffect(() => {
    async function fetchVideos() {
      try {
        const url = `https://www.googleapis.com/youtube/v3/search?key=${YOUTUBE_API_KEY}&channelId=${YOUTUBE_CHANNEL_ID}&part=snippet&order=date&maxResults=6&type=video`;
        const res = await fetch(url, {
          signal: (() => { const c = new AbortController(); setTimeout(() => c.abort(), 8000); return c.signal; })()
        });
        if (!res.ok) {
          const errData = await res.json().catch(() => ({}));
          console.warn("YouTube API error:", errData?.error?.message || res.status);
          setApiError(true);
          setLoading(false);
          return;
        }
        const data = await res.json();
        const items = data.items || [];
        setVideos(items);
        if (items.length === 0) setApiError(true);
      } catch (e) {
        console.warn("YouTube fetch error:", e.message);
        setApiError(true);
      }
      setLoading(false);
    }
    fetchVideos();
  }, []);

  const CHANNEL_URL = `https://www.youtube.com/channel/${YOUTUBE_CHANNEL_ID}`;

  const [currentIdx, setCurrentIdx] = useState(0);

  const header = (
    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 10 }}>
      <span style={{ fontSize: 16 }}>▶️</span>
      <div style={{ flex: 1 }}>
        <div style={{ fontFamily: "var(--font-display)", fontSize: 13, fontWeight: 600, color: C.dark }}>
          Canal YouTube
        </div>
      </div>
      <a href={CHANNEL_URL} target="_blank" rel="noopener noreferrer"
        style={{ fontSize: 11, color: C.primary, fontWeight: 600, textDecoration: "none" }}>
        Ver →
      </a>
    </div>
  );

  if (loading) return <div>{header}<Spinner /></div>;

  if (apiError || videos.length === 0) {
    return (
      <div>
        {header}
        <div style={{
          display: "flex", alignItems: "center", gap: 10,
          background: "#fff1f2", border: "1px solid #fecdd3",
          borderRadius: 12, padding: "10px 12px",
        }}>
          <div style={{
            width: 36, height: 36, background: "#ff0000", borderRadius: 10,
            display: "flex", alignItems: "center", justifyContent: "center", flexShrink: 0,
          }}>
            <span style={{ fontSize: 16, color: "white" }}>▶</span>
          </div>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 11, fontWeight: 600, color: C.dark, marginBottom: 2 }}>API no habilitada aún</div>
            <div style={{ fontSize: 10, color: C.gray }}>Habilita YouTube Data API v3 en Google Cloud</div>
          </div>
          <a href={CHANNEL_URL} target="_blank" rel="noopener noreferrer"
            style={{ flexShrink: 0, background: "#ff0000", color: "white", borderRadius: 9, padding: "5px 10px", fontSize: 11, fontWeight: 600, textDecoration: "none" }}>
            Canal
          </a>
        </div>
      </div>
    );
  }

  const current = videos[currentIdx];
  const vid = current?.id?.videoId;
  const title = current?.snippet?.title || "";
  const date = current?.snippet?.publishedAt
    ? new Date(current.snippet.publishedAt).toLocaleDateString("es-CL", { day: "numeric", month: "long" })
    : "";

  return (
    <div>
      {header}

      {/* Player embed inline */}
      <div style={{ borderRadius: 12, overflow: "hidden", background: "#000", position: "relative", paddingTop: "56.25%" }}>
        <iframe
          key={vid}
          src={`https://www.youtube.com/embed/${vid}?autoplay=0`}
          style={{ position: "absolute", inset: 0, width: "100%", height: "100%", border: "none" }}
          allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
          allowFullScreen
        />
      </div>

      {/* Título + controles prev/next */}
      <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 8 }}>
        <button
          onClick={() => setCurrentIdx(i => Math.max(0, i - 1))}
          disabled={currentIdx === 0}
          style={{ background: "none", border: `1px solid ${C.border}`, borderRadius: 9, width: 28, height: 28, cursor: currentIdx === 0 ? "not-allowed" : "pointer", opacity: currentIdx === 0 ? 0.3 : 1, fontSize: 12, flexShrink: 0 }}
        >‹</button>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontSize: 11, fontWeight: 600, color: C.dark, lineHeight: 1.3, overflow: "hidden", display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical" }}>
            {title}
          </div>
          <div style={{ fontSize: 10, color: C.gray, marginTop: 2 }}>{date} · {currentIdx + 1}/{videos.length}</div>
        </div>
        <button
          onClick={() => setCurrentIdx(i => Math.min(videos.length - 1, i + 1))}
          disabled={currentIdx === videos.length - 1}
          style={{ background: "none", border: `1px solid ${C.border}`, borderRadius: 9, width: 28, height: 28, cursor: currentIdx === videos.length - 1 ? "not-allowed" : "pointer", opacity: currentIdx === videos.length - 1 ? 0.3 : 1, fontSize: 12, flexShrink: 0 }}
        >›</button>
      </div>
    </div>
  );
}

