//  DOCUMENTOS
// ══════════════════════════════════════════
function Documentos({ docs, onReload }) {
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({
    nombre: "",
    url: "",
    categoria: "Repertorio",
    size: "",
  });
  const [saving, setSaving] = useState(false);

  async function submit() {
    if (!form.nombre || !form.url) return;
    setSaving(true);
    try {
      await supabase("documentos", { method: "POST", body: form });
      sendPushToAll("📄 Nuevo documento en el Coro", form.nombre, "/");
      setForm({ nombre: "", url: "", categoria: "Repertorio", size: "" });
      setShowForm(false);
      onReload();
    } catch (e) {
      alert("Error: " + e.message);
    }
    setSaving(false);
  }

  return (
    <div style={{ maxWidth: 800 }}>
      <SectionTitle
        title="Descargas Misas"
        subtitle="Archivos del coro"
        action={<Btn onClick={() => setShowForm(true)}>+ Agregar</Btn>}
      />
      {showForm && (
        <Card style={{ marginBottom: 16, border: `1px solid ${C.primary}40` }}>
          <div
            style={{
              fontFamily: "var(--font-display)",
              fontSize: 14,
              fontWeight: 600,
              color: C.dark,
              marginBottom: 14,
            }}
          >
            Nuevo documento
          </div>
          <input
            placeholder="Nombre del archivo *"
            value={form.nombre}
            onChange={(e) => setForm((p) => ({ ...p, nombre: e.target.value }))}
            style={{
              width: "100%",
              padding: "10px 14px",
              borderRadius: 10,
              border: `1px solid ${C.border}`,
              fontSize: 13,
              outline: "none",
              marginBottom: 10,
              boxSizing: "border-box",
            }}
          />
          <input
            placeholder="URL (Google Drive, Dropbox...) *"
            value={form.url}
            onChange={(e) => setForm((p) => ({ ...p, url: e.target.value }))}
            style={{
              width: "100%",
              padding: "10px 14px",
              borderRadius: 10,
              border: `1px solid ${C.border}`,
              fontSize: 13,
              outline: "none",
              marginBottom: 10,
              boxSizing: "border-box",
            }}
          />
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: 10,
              marginBottom: 12,
            }}
          >
            <select
              value={form.categoria}
              onChange={(e) =>
                setForm((p) => ({ ...p, categoria: e.target.value }))
              }
              style={{
                padding: "10px 14px",
                borderRadius: 10,
                border: `1px solid ${C.border}`,
                fontSize: 13,
                outline: "none",
              }}
            >
              {[
                "Repertorio",
                "Partituras",
                "Organización",
                "Comunicados",
                "Otro",
              ].map((c) => (
                <option key={c}>{c}</option>
              ))}
            </select>
            <input
              placeholder="Tamaño (ej: 2.3 MB)"
              value={form.size}
              onChange={(e) => setForm((p) => ({ ...p, size: e.target.value }))}
              style={{
                padding: "10px 14px",
                borderRadius: 10,
                border: `1px solid ${C.border}`,
                fontSize: 13,
                outline: "none",
              }}
            />
          </div>
          <div style={{ display: "flex", gap: 8 }}>
            <Btn onClick={submit} disabled={saving}>
              {saving ? "Guardando..." : "Guardar"}
            </Btn>
            <Btn variant="ghost" onClick={() => setShowForm(false)}>
              Cancelar
            </Btn>
          </div>
        </Card>
      )}
      {docs.map((d) => (
        <Card
          key={d.id}
          hover
          style={{
            display: "flex",
            alignItems: "center",
            gap: 14,
            marginBottom: 10,
            flexWrap: "wrap",
          }}
        >
          <div
            style={{
              width: 44,
              height: 44,
              background: "#ffffff",
              borderRadius: 12,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              flexShrink: 0,
            }}
          >
            <img src="data:image/png;base64," alt="PDF" style={{ width:26, height:26, objectFit:"contain" }} />
          </div>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div
              style={{
                fontSize: 14,
                fontWeight: 500,
                color: C.dark,
                overflow: "hidden",
                textOverflow: "ellipsis",
                whiteSpace: "nowrap",
              }}
            >
              {d.nombre}
            </div>
            <div style={{ fontSize: 12, color: C.gray, marginTop: 2 }}>
              <Badge>{d.categoria}</Badge>
              {d.size ? " · " + d.size : ""}
            </div>
          </div>
          <a href={d.url} target="_blank" rel="noopener">
            <Btn variant="ghost" style={{ flexShrink: 0 }}>
              ⬇ Abrir
            </Btn>
          </a>
        </Card>
      ))}
    </div>
  );
}

// ══════════════════════════════════════════
//  ORACIONES
// ══════════════════════════════════════════
function Oraciones({ oraciones, user, onReload }) {
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({ titulo: "", texto: "" });
  const [saving, setSaving] = useState(false);

  async function submit() {
    if (!form.titulo || !form.texto) return;
    setSaving(true);
    try {
      await supabase("oraciones", {
        method: "POST",
        body: { ...form, autor: user.nombre },
      });
      setForm({ titulo: "", texto: "" });
      setShowForm(false);
      onReload();
    } catch (e) {
      alert("Error: " + e.message);
    }
    setSaving(false);
  }

  return (
    <div style={{ maxWidth: 800 }}>
      <SectionTitle
        title="Oraciones"
        subtitle="Compartidas por los integrantes"
        action={<Btn onClick={() => setShowForm(true)}>+ Nueva</Btn>}
      />
      {showForm && (
        <Card style={{ marginBottom: 16, border: `1px solid ${C.primary}40` }}>
          <input
            placeholder="Título *"
            value={form.titulo}
            onChange={(e) => setForm((p) => ({ ...p, titulo: e.target.value }))}
            style={{
              width: "100%",
              padding: "10px 14px",
              borderRadius: 10,
              border: `1px solid ${C.border}`,
              fontSize: 13,
              outline: "none",
              marginBottom: 10,
              boxSizing: "border-box",
            }}
          />
          <textarea
            value={form.texto}
            onChange={(e) => setForm((p) => ({ ...p, texto: e.target.value }))}
            placeholder="Texto de la oración..."
            rows={4}
            style={{
              width: "100%",
              padding: "10px 14px",
              borderRadius: 10,
              border: `1px solid ${C.border}`,
              fontSize: 13,
              fontFamily: "Inter,sans-serif",
              resize: "vertical",
              boxSizing: "border-box",
              outline: "none",
              marginBottom: 12,
            }}
          />
          <div style={{ display: "flex", gap: 8 }}>
            <Btn onClick={submit} disabled={saving}>
              {saving ? "Publicando..." : "Publicar"}
            </Btn>
            <Btn variant="ghost" onClick={() => setShowForm(false)}>
              Cancelar
            </Btn>
          </div>
        </Card>
      )}
      {oraciones.map((o) => (
        <Card
          key={o.id}
          style={{ marginBottom: 12, borderLeft: `4px solid ${C.gold}` }}
        >
          <div
            style={{
              fontFamily: "var(--font-display)",
              fontSize: 14,
              fontWeight: 600,
              color: C.dark,
              marginBottom: 8,
            }}
          >
            ✦ {o.titulo}
          </div>
          <p
            style={{
              lineHeight: 1.8,
              color: "var(--text-secondary)",
              margin: "0 0 12px",
              fontSize: 14,
            }}
          >
            {o.texto}
          </p>
          <div style={{ fontSize: 11, color: C.gray }}>
            👤 {o.autor} · {new Date(o.created_at).toLocaleDateString("es-CL")}
          </div>
        </Card>
      ))}
    </div>
  );
}

