const NOTAS_CROMATICAS = ["C","C#","D","D#","E","F","F#","G","G#","A","A#","B"];

// Nombres en formato latinoamericano (Do, Re, Mi...)
const NOTA_LATINA = {
  "C":  "Do",
  "C#": "Do#",
  "D":  "Re",
  "D#": "Re#",
  "E":  "Mi",
  "F":  "Fa",
  "F#": "Fa#",
  "G":  "Sol",
  "G#": "Sol#",
  "A":  "La",
  "A#": "La#",
  "B":  "Si",
};
function notaLatina(nota) { return NOTA_LATINA[nota] || nota; }

// Google Drive Picker (OAuth client-only, sin secreto)
// ID de la carpeta pública de Google Drive con los PDFs del cancionero
const GDRIVE_FOLDER_ID = "18AqJFgonJlvXh-CxZuKRQC2oXLVK2BjF";
const GDRIVE_API_KEY   = "AIzaSyAHncVhw60TS60FQIvwUwfGkLsJEO4XTuE";

// Lista todos los PDFs de la carpeta pública sin OAuth
async function listarPDFsDrive(busqueda = "") {
  let q = `'${GDRIVE_FOLDER_ID}' in parents and mimeType='application/pdf' and trashed=false`;
  if (busqueda.trim()) q += ` and name contains '${busqueda.trim().replace(/'/g, "\\'")}'`;
  const url = `https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(q)}&key=${GDRIVE_API_KEY}&fields=files(id,name)&orderBy=name&pageSize=200`;
  const res = await fetch(url);
  if (!res.ok) throw new Error("No se pudo acceder a la carpeta de Drive");
  const data = await res.json();
  return (data.files || []).map(f => ({
    id: f.id,
    nombre: f.name.replace(/\.pdf$/i, ""),
    url: `https://drive.google.com/file/d/${f.id}/view`,
  }));
}

// Lista TODOS los PDFs sin filtro (para el directorio completo)
async function listarTodosDrive() {
  let allFiles = [];
  let pageToken = null;
  do {
    const q = `'${GDRIVE_FOLDER_ID}' in parents and mimeType='application/pdf' and trashed=false`;
    let url = `https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(q)}&key=${GDRIVE_API_KEY}&fields=files(id,name),nextPageToken&orderBy=name&pageSize=200`;
    if (pageToken) url += `&pageToken=${pageToken}`;
    const res = await fetch(url);
    if (!res.ok) break;
    const data = await res.json();
    allFiles = allFiles.concat(data.files || []);
    pageToken = data.nextPageToken || null;
  } while (pageToken);
  return allFiles.map(f => ({
    id: f.id,
    nombre: f.name.replace(/\.pdf$/i, ""),
    url: `https://drive.google.com/file/d/${f.id}/view`,
  }));
}

function transponerAcorde(acorde, semis) {
  if (!acorde || semis === 0) return acorde;
  const flatMap = { Db:"C#", Eb:"D#", Fb:"E", Gb:"F#", Ab:"G#", Bb:"A#", Cb:"B" };
  const regex = /^([A-G][#b]?)(.*)/;
  const m = acorde.match(regex);
  if (!m) return acorde;
  const rawNote = m[1];
  const suffix  = m[2];
  const normalizado = flatMap[rawNote] || rawNote;
  const idx = NOTAS_CROMATICAS.indexOf(normalizado);
  if (idx === -1) return acorde;
  const newIdx = ((idx + semis) % 12 + 12) % 12;
  return NOTAS_CROMATICAS[newIdx] + suffix;
}

function transponerLinea(linea, semis) {
  // Detecta si la línea es de acordes: >= 50% de tokens son acordes
  if (semis === 0) return linea;
  const tokens = linea.trim().split(/\s+/);
  if (tokens.length === 0) return linea;
  const acordeRe = /^[A-G][#b]?(m|maj|min|dim|aug|sus|add)?\d*(\/[A-G][#b]?)?$/;
  const contAcordes = tokens.filter(t => acordeRe.test(t)).length;
  if (contAcordes / tokens.length < 0.5) return linea;
  return tokens.map(t => acordeRe.test(t) ? transponerAcorde(t, semis) : t).join(" ");
}

function transponerTextoCompleto(texto, semis) {
  if (!texto || semis === 0) return texto;
  return texto.split("\n").map(l => transponerLinea(l, semis)).join("\n");
}

function drivePreviewUrl(url) {
  if (!url) return "";
  // Convertir cualquier variante de URL de Drive a preview embebible
  return url
    .replace(/\/view(\?.*)?$/, "/preview")
    .replace(/\/edit(\?.*)?$/, "/preview");
}

// ── Componente QR pequeño usando api.qrserver.com (gratis, sin clave) ──
function QRImg({ data, size = 120, borderColor = "#1a3a2a" }) {
  if (!data) return null;
  const src = `https://api.qrserver.com/v1/create-qr-code/?size=${size}x${size}&data=${encodeURIComponent(data)}&color=1a3a2a&bgcolor=ffffff&margin=8`;
  return (
    <div style={{
      background: "white", borderRadius: 12, padding: 6,
      border: `2px solid ${borderColor}`,
      boxShadow: "0 2px 8px rgba(0,0,0,0.12)",
      display: "inline-block",
    }}>
      <img src={src} alt="QR" width={size} height={size} style={{ display: "block", borderRadius: 4 }} />
    </div>
  );
}

// ══════════════════════════════════════════════════════════════════
//  CANCIONERO — Componente principal
// ══════════════════════════════════════════════════════════════════
function Cancionero({ user }) {
  const isAdmin = user?.cuerda === "Admin";

  // Vistas: "buscar" | "directorio" | "visor" | "pautas" | "nueva_pauta" | "ver_pauta"
  const [vista, setVista] = useState("directorio");

  // Canciones guardadas en Supabase y pautas
  const [canciones, setCanciones] = useState([]);
  const [pautas, setPautas]       = useState([]);
  const [loading, setLoading]     = useState(true);

  // Ítem activo en el visor
  const [cancionActiva, setCancionActiva] = useState(null);
  const [pautaActiva, setPautaActiva]     = useState(null);

  // Vista previa del visor (qué tab se abrió desde)
  const [vistaAnterior, setVistaAnterior] = useState("directorio");

  useEffect(() => { cargar(); }, []);

  async function cargar() {
    setLoading(true);
    try {
      const [c, p] = await Promise.all([
        supabase("cancionero_canciones", { order: "&order=nombre.asc" }).catch(() => []),
        supabase("cancionero_pautas",    { order: "&order=fecha.desc" }).catch(() => []),
      ]);
      setCanciones(Array.isArray(c) ? c : []);
      setPautas(Array.isArray(p) ? p : []);
    } catch {}
    setLoading(false);
  }

  function abrirVisor(cancion, desde = null) {
    setCancionActiva(cancion);
    setVistaAnterior(desde || vista);
    setVista("visor");
  }
  function abrirPauta(pauta) { setPautaActiva(pauta); setVista("ver_pauta"); }

  const TAB_ITEMS = [
    { id: "directorio", icon: "📂", label: "Directorio" },
    { id: "buscar",     icon: "🔍", label: "Mis canciones" },
    { id: "pautas",     icon: "📋", label: "Pautas de Misa" },
  ];

  const enSubvista = ["visor","nueva_pauta","ver_pauta"].includes(vista);

  return (
    <div style={{ maxWidth: 1100 }}>
      {/* ── Encabezado ── */}
      <div style={{
        background: `linear-gradient(135deg,${C.primaryDark},${C.primary})`,
        borderRadius: 16, padding: "20px 24px", marginBottom: 20,
        display: "flex", alignItems: "center", gap: 16, flexWrap: "wrap",
      }}>
        <div style={{
          width: 52, height: 52, background: "rgba(255,255,255,0.2)", borderRadius: 18,
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, flexShrink: 0,
        }}>🎼</div>
        <div>
          <div style={{ fontFamily: "var(--font-display)", fontSize: 20, fontWeight: 700, color: "white" }}>
            Cancionero Digital
          </div>
          <div style={{ fontSize: 12, color: "rgba(255,255,255,0.8)" }}>
            Letras · Acordes · Pautas de Misa · QR
          </div>
        </div>
        <div style={{ marginLeft: "auto", display: "flex", gap: 8 }}>
          {[{ n: canciones.length, l: "Guardadas" }, { n: pautas.length, l: "Pautas" }].map((s, i) => (
            <div key={i} style={{ background: "rgba(255,255,255,0.2)", borderRadius: 12, padding: "8px 14px", textAlign: "center" }}>
              <div style={{ fontSize: 20, fontWeight: 700, color: "white", lineHeight: 1 }}>{s.n}</div>
              <div style={{ fontSize: 10, color: "rgba(255,255,255,0.85)", marginTop: 2 }}>{s.l}</div>
            </div>
          ))}
        </div>
      </div>

      {/* ── Tabs ── */}
      {!enSubvista && (
        <div style={{ display: "flex", gap: 6, marginBottom: 20, overflowX: "auto", paddingBottom: 4 }}>
          {TAB_ITEMS.map(t => (
            <button key={t.id} onClick={() => setVista(t.id)} style={{
              padding: "8px 18px", borderRadius: 10, border: "none", cursor: "pointer",
              fontSize: 13, fontWeight: vista === t.id ? 600 : 400, whiteSpace: "nowrap",
              background: vista === t.id ? C.primary : "transparent",
              color: vista === t.id ? "white" : C.gray, transition: "all 0.15s",
            }}>{t.icon} {t.label}</button>
          ))}
          {isAdmin && vista === "pautas" && (
            <button onClick={() => setVista("nueva_pauta")} style={{
              marginLeft: "auto", padding: "8px 18px", borderRadius: 10, border: `1px solid ${C.primary}`,
              background: C.primaryLight, color: C.primaryDark, fontSize: 13, fontWeight: 600, cursor: "pointer",
            }}>📋 Nueva Pauta</button>
          )}
        </div>
      )}

      {loading ? <Spinner /> : (
        <>
          {vista === "directorio"  && <CancioneroDirectorio canciones={canciones} isAdmin={isAdmin} onAbrir={(c) => abrirVisor(c, "directorio")} />}
          {vista === "buscar"      && <CancioneroBuscador canciones={canciones} isAdmin={isAdmin} onAbrir={(c) => abrirVisor(c, "buscar")} onReload={cargar} />}
          {vista === "visor"       && <CancioneroVisor cancion={cancionActiva} isAdmin={isAdmin} onVolver={() => setVista(vistaAnterior)} onReload={cargar} canciones={canciones} />}
          {vista === "pautas"      && <CancioneroPautas pautas={pautas} canciones={canciones} isAdmin={isAdmin} onAbrir={abrirPauta} onNueva={() => setVista("nueva_pauta")} onReload={cargar} />}
          {vista === "nueva_pauta" && <CancioneroFormPauta canciones={canciones} onGuardado={() => { cargar(); setVista("pautas"); }} onCancelar={() => setVista("pautas")} />}
          {vista === "ver_pauta"   && <CancioneroDetallePauta pauta={pautaActiva} canciones={canciones} isAdmin={isAdmin} onVolver={() => setVista("pautas")} onReload={cargar} />}
        </>
      )}
    </div>
  );
}

