// ══════════════════════════════════════════
//  ASISTENCIA (vista pública)
// ══════════════════════════════════════════
function Asistencia({ asistencia, members, eventos, user, onReload }) {
  const eventosConAsistencia = eventos.filter(e =>
    asistencia.some(a => a.evento_id === e.id)
  ).sort((a, b) => new Date(b.fecha) - new Date(a.fecha));

  const calcPct = (memberId) => {
    const misReg = asistencia.filter(a => a.member_id === memberId);
    const evaluados = misReg.filter(a => !["justificado","excluido","nuevo"].includes(a.estado));
    const presentes = evaluados.filter(a => a.estado === "presente").length;
    return evaluados.length > 0 ? Math.round((presentes / evaluados.length) * 100) : null;
  };

  const colorPct = (pct) => pct === null ? C.gray : pct >= 75 ? C.primary : pct >= 50 ? "#f59e0b" : "#ef4444";
  const fmtFecha = (f) => new Date(f + "T00:00:00").toLocaleDateString("es-CL", { day: "numeric", month: "short" });
  const [eventoSeleccionado, setEventoSeleccionado] = useState(null);

  const isAdmin = user?.cuerda === "Admin";
  const cc = CUERDAS[user?.cuerda] || C.primary;

  // Datos personales del usuario logueado
  const misReg = asistencia.filter(a => a.member_id === user?.id);
  const misPresentes = misReg.filter(a => a.estado === "presente").length;
  const misAusentes = misReg.filter(a => a.estado === "ausente").length;
  const misJustificados = misReg.filter(a => a.estado === "justificado").length;
  const misExcluidos = misReg.filter(a => a.estado === "excluido").length;
  const misNuevos = misReg.filter(a => a.estado === "nuevo").length;
  const evaluados = misReg.filter(a => !["justificado","excluido","nuevo"].includes(a.estado)).length;
  const pct = calcPct(user?.id);
  const colPct = colorPct(pct);
  const circum = 2 * Math.PI * 38;
  const tieneEstrella = misPresentes > 0 && misAusentes === 0 && misJustificados === 0;

  const msgPct = pct === null ? null : pct >= 75 ? "¡Vas muy bien! Sigue así 💪" : pct >= 50 ? "Puedes mejorar tu asistencia 🎵" : "Tu asistencia necesita atención ⚠️";
  const bgPct = pct === null ? C.bg : pct >= 75 ? C.primary + "12" : pct >= 50 ? "#fef3c7" : "#fee2e2";
  const borderPct = pct === null ? C.border : pct >= 75 ? C.primary + "40" : pct >= 50 ? "#f59e0b40" : "#ef444440";

  return (
    <div style={{ maxWidth: 1000 }}>
      <SectionTitle title="Asistencia del Coro" subtitle="Registro de asistencia a eventos y ensayos" />

      {/* ── WIDGET PERSONAL ── */}
      <div style={{ background: bgPct, border: `2px solid ${borderPct}`, borderRadius: 18, padding: 20, marginBottom: 20, display: "flex", alignItems: "center", gap: 20, flexWrap: "wrap" }}>

        {/* Anillo SVG */}
        <div style={{ position: "relative", width: 96, height: 96, flexShrink: 0 }}>
          <svg width="96" height="96" style={{ transform: "rotate(-90deg)" }}>
            <circle cx="48" cy="48" r="38" fill="none" stroke="#e5e7eb" strokeWidth="7" />
            {pct !== null && (
              <circle cx="48" cy="48" r="38" fill="none"
                stroke={colPct} strokeWidth="7"
                strokeDasharray={`${(pct / 100) * circum} ${circum}`}
                strokeLinecap="round"
                style={{ transition: "stroke-dasharray 0.6s ease" }}
              />
            )}
          </svg>
          <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
            {pct !== null ? (
              <>
                <span style={{ fontSize: 20, fontWeight: 800, color: colPct, lineHeight: 1 }}>{pct}%</span>
                {tieneEstrella
                  ? <span style={{ fontSize: 16, lineHeight: 1, marginTop: 1 }}>⭐</span>
                  : <span style={{ fontSize: 9, color: C.gray, fontWeight: 600, marginTop: 1 }}>asistencia</span>
                }
              </>
            ) : (
              <span style={{ fontSize: 10, color: C.gray, textAlign: "center", lineHeight: 1.3, padding: "0 8px" }}>sin datos</span>
            )}
          </div>
        </div>

        {/* Info personal */}
        <div style={{ flex: 1, minWidth: 180 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 8 }}>
            <div style={{ width: 40, height: 40, borderRadius: "50%", background: cc, overflow: "hidden", display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 14, fontWeight: 700, flexShrink: 0 }}>
              {user?.foto_url ? <img src={user.foto_url} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : ini(user?.nombre || "U")}
            </div>
            <div>
              <div style={{ fontWeight: 700, fontSize: 15, color: C.dark }}>{user?.nombre?.split(" ")[0]}</div>
              {!esVisita(user) && <div style={{ fontSize: 11, color: cc, fontWeight: 600 }}>{rolFullLabel(user)}</div>}
            </div>
          </div>
          {msgPct && <div style={{ fontSize: 12, color: colPct, fontWeight: 600, marginBottom: 10, display: "flex", alignItems: "center", gap: 4 }}>{msgPct}{tieneEstrella && <span style={{ fontSize: 16 }}>⭐</span>}</div>}

          {/* Contadores */}
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
            {[
              { label: "Presentes", val: misPresentes, color: C.primary, bg: C.primaryLight, emoji: "✅" },
              { label: "Ausentes", val: misAusentes, color: "#ef4444", bg: "#fee2e2", emoji: "❌" },
              { label: "Justificados", val: misJustificados, color: "#f59e0b", bg: "#fef3c7", emoji: "🟡" },
            ].map(s => (
              <div key={s.label} style={{ background: s.bg, border: `1px solid ${s.color}30`, borderRadius: 12, padding: "6px 12px", textAlign: "center", minWidth: 70 }}>
                <div style={{ fontSize: 11, color: s.color, marginBottom: 1 }}>{s.emoji} {s.label}</div>
                <div style={{ fontSize: 18, fontWeight: 800, color: s.color }}>{s.val}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Historial personal por evento */}
        {misReg.length > 0 && (
          <div style={{ width: "100%", marginTop: 4 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: C.gray, marginBottom: 8, textTransform: "uppercase", letterSpacing: "0.05em" }}>Mis últimos eventos</div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
              {eventosConAsistencia.slice(0, 8).map(e => {
                const reg = misReg.find(a => a.evento_id === e.id);
                const estado = reg?.estado;
                if (!estado) return null;
                const color = estado === "presente" ? C.primary : estado === "justificado" ? "#f59e0b" : estado === "excluido" ? "#8b5cf6" : estado === "nuevo" ? "#06b6d4" : "#ef4444";
                const icono = estado === "presente" ? "✅" : estado === "justificado" ? "🟡" : estado === "excluido" ? "🔵" : estado === "nuevo" ? "🆕" : "❌";
                const tipoEmoji = e.tipo === "ensayo" ? "🎵" : e.tipo === "misa" ? "⛪" : "📅";
                return (
                  <div key={e.id} style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 3, background: color + "15", border: `1px solid ${color}30`, borderRadius: 12, padding: "6px 10px", fontSize: 11 }}>
                    <span style={{ fontSize: 16 }}>{icono}</span>
                    <span style={{ color: C.dark, fontWeight: 600, textAlign: "center", maxWidth: 80, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{tipoEmoji} {e.titulo.split(" ").slice(0, 2).join(" ")}</span>
                    <span style={{ color: C.gray, fontSize: 10 }}>{fmtFecha(e.fecha)}</span>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* ── TABLA GENERAL (solo Admin) ── */}
      {isAdmin && (
        <>
          <Card style={{ marginBottom: 20, padding: 0, overflow: "hidden" }}>
            <div style={{ padding: "14px 18px", borderBottom: `1px solid ${C.border}`, display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ fontSize: 18 }}>📊</span>
              <span style={{ fontWeight: 700, fontSize: 15, color: C.dark }}>Resumen por integrante</span>
            </div>
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
                <thead>
                  <tr style={{ background: C.bg }}>
                    <th style={{ padding: "10px 16px", textAlign: "left", color: C.gray, fontWeight: 600 }}>Integrante</th>
                    <th style={{ padding: "10px 16px", textAlign: "center", color: C.gray, fontWeight: 600 }}>Presentes</th>
                    <th style={{ padding: "10px 16px", textAlign: "center", color: C.gray, fontWeight: 600 }}>Ausentes</th>
                    <th style={{ padding: "10px 16px", textAlign: "center", color: C.gray, fontWeight: 600 }}>Justificados</th>
                    <th style={{ padding: "10px 16px", textAlign: "center", color: C.gray, fontWeight: 600 }}>Asistencia</th>
                  </tr>
                </thead>
                <tbody>
                  {members.map((m, i) => {
                    const mReg = asistencia.filter(a => a.member_id === m.id);
                    const presentes = mReg.filter(a => a.estado === "presente").length;
                    const ausentes = mReg.filter(a => a.estado === "ausente").length;
                    const justificados = mReg.filter(a => a.estado === "justificado").length;
                    const excluidos = mReg.filter(a => a.estado === "excluido").length;
                    const nuevos = mReg.filter(a => a.estado === "nuevo").length;
                    const p = calcPct(m.id);
                    const mcc = CUERDAS[m.cuerda] || C.primary;
                    return (
                      <tr key={m.id} style={{ borderTop: `1px solid ${C.border}`, background: m.id === user?.id ? C.primaryLight + "40" : i % 2 === 0 ? "#fff" : C.bg }}>
                        <td style={{ padding: "10px 16px" }}>
                          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                            <div style={{ width: 32, height: 32, borderRadius: "50%", background: mcc, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 12, fontWeight: 700, flexShrink: 0, overflow: "hidden" }}>
                              {m.foto_url ? <img src={m.foto_url} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : ini(m.nombre || "?")}
                            </div>
                            <div>
                              <div style={{ fontWeight: 600, color: C.dark }}>{m.nombre} {m.id === user?.id && <span style={{ fontSize: 10, color: C.primary }}>(tú)</span>}</div>
                              <div style={{ fontSize: 11, color: mcc }}>{rolFullLabel(m)}</div>
                            </div>
                          </div>
                        </td>
                        <td style={{ padding: "10px 16px", textAlign: "center", color: C.primary, fontWeight: 600 }}>{presentes}</td>
                        <td style={{ padding: "10px 16px", textAlign: "center", color: "#ef4444", fontWeight: 600 }}>{ausentes}</td>
                        <td style={{ padding: "10px 16px", textAlign: "center", color: "#f59e0b", fontWeight: 600 }}>{justificados}</td>
                        <td style={{ padding: "10px 16px", textAlign: "center" }}>
                          {p !== null ? (
                            <div style={{ display: "inline-flex", alignItems: "center", gap: 6 }}>
                              <div style={{ width: 60, height: 6, borderRadius: 3, background: "#e5e7eb", overflow: "hidden" }}>
                                <div style={{ width: `${p}%`, height: "100%", background: colorPct(p), borderRadius: 3, transition: "width 0.3s" }} />
                              </div>
                              <span style={{ fontWeight: 700, color: colorPct(p), fontSize: 13 }}>{p}%</span>
                              {ausentes === 0 && justificados === 0 && presentes > 0 && <span title="¡Sin ausencias!" style={{ fontSize: 14, lineHeight: 1 }}>⭐</span>}
                            </div>
                          ) : (
                            <span style={{ color: C.gray, fontSize: 12 }}>Sin registros</span>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </Card>

          {/* Detalle por evento */}
          <Card style={{ padding: 0, overflow: "hidden" }}>
            <div style={{ padding: "14px 18px", borderBottom: `1px solid ${C.border}`, display: "flex", alignItems: "center", gap: 8 }}>
              <span style={{ fontSize: 18 }}>📅</span>
              <span style={{ fontWeight: 700, fontSize: 15, color: C.dark }}>Detalle por evento</span>
            </div>
            {eventosConAsistencia.length === 0 ? (
              <div style={{ padding: 32, textAlign: "center", color: C.gray }}>No hay registros de asistencia aún.</div>
            ) : (
              <div>
                {eventosConAsistencia.map(e => {
                  const regEvento = asistencia.filter(a => a.evento_id === e.id);
                  const presentes = regEvento.filter(a => a.estado === "presente").length;
                  const total = regEvento.filter(a => !["justificado","excluido","nuevo"].includes(a.estado)).length;
                  const p = total > 0 ? Math.round((presentes / total) * 100) : 0;
                  const isOpen = eventoSeleccionado === e.id;
                  return (
                    <div key={e.id} style={{ borderTop: `1px solid ${C.border}` }}>
                      <div onClick={() => setEventoSeleccionado(isOpen ? null : e.id)} style={{ padding: "12px 18px", cursor: "pointer", display: "flex", alignItems: "center", gap: 12, background: isOpen ? C.primaryLight + "30" : "transparent" }}>
                        <div style={{ width: 40, height: 40, borderRadius: 12, background: C.primary + "15", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", flexShrink: 0 }}>
                          <div style={{ fontSize: 14, fontWeight: 800, color: C.primary, lineHeight: 1 }}>{new Date(e.fecha + "T00:00:00").getDate()}</div>
                          <div style={{ fontSize: 8, color: C.primary, textTransform: "uppercase" }}>{new Date(e.fecha + "T00:00:00").toLocaleDateString("es-CL", { month: "short" })}</div>
                        </div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontWeight: 600, color: C.dark, fontSize: 13 }}>{e.titulo}</div>
                          <div style={{ fontSize: 11, color: C.gray }}>{presentes} presentes · {regEvento.filter(a => a.estado === "ausente").length} ausentes · {regEvento.filter(a => a.estado === "justificado").length} justificados{regEvento.filter(a => a.estado === "excluido").length > 0 ? ` · ${regEvento.filter(a => a.estado === "excluido").length} 🔵` : ""}{regEvento.filter(a => a.estado === "nuevo").length > 0 ? ` · ${regEvento.filter(a => a.estado === "nuevo").length} 🆕` : ""}</div>
                        </div>
                        <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                          <span style={{ fontWeight: 700, color: colorPct(p), fontSize: 14 }}>{p}%</span>
                          <span style={{ color: C.gray, fontSize: 12 }}>{isOpen ? "▲" : "▼"}</span>
                        </div>
                      </div>
                      {isOpen && (
                        <div style={{ padding: "8px 18px 16px", display: "flex", flexWrap: "wrap", gap: 8 }}>
                          {members.map(m => {
                            const reg = regEvento.find(a => a.member_id === m.id);
                            const estado = reg?.estado || "sin registro";
                            const color = estado === "presente" ? C.primary : estado === "justificado" ? "#f59e0b" : estado === "ausente" ? "#ef4444" : estado === "excluido" ? "#8b5cf6" : estado === "nuevo" ? "#06b6d4" : C.gray;
                            const icono = estado === "presente" ? "✅" : estado === "justificado" ? "🟡" : estado === "ausente" ? "❌" : estado === "excluido" ? "🔵" : estado === "nuevo" ? "🆕" : "⬜";
                            return (
                              <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 6, background: color + "15", border: `1px solid ${color}30`, borderRadius: 20, padding: "4px 10px", fontSize: 12 }}>
                                <span>{icono}</span>
                                <span style={{ color: C.dark, fontWeight: 500 }}>{m.nombre.split(" ")[0]}</span>
                              </div>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </Card>
        </>
      )}
    </div>
  );
}

// ══════════════════════════════════════════
//  ADMIN ASISTENCIA
// ══════════════════════════════════════════
function AdminAsistencia({ members, eventos, asistencia: asistenciaProp, onReload }) {
  // eventos = gcalEventos (Google Calendar)
  const [eventoId, setEventoId] = useState("");
  const [registros, setRegistros] = useState({});
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [gcalLoading, setGcalLoading] = useState(false);
  const [gcalEventos, setGcalEventos] = useState(eventos || []);
  // Copia local de asistencia para siempre tener datos frescos
  const [asistenciaLocal, setAsistenciaLocal] = useState(asistenciaProp || []);

  // Sincronizar asistenciaLocal cuando cambia la prop del padre
  useEffect(() => {
    setAsistenciaLocal(asistenciaProp || []);
  }, [asistenciaProp]);

  // Función para recargar asistencia directamente desde Supabase
  const recargarAsistencia = async () => {
    try {
      const token = _authToken || SUPABASE_KEY;
      const res = await fetch(`${SUPABASE_URL}/rest/v1/asistencia?select=*&order=created_at.desc`, {
        headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${token}` },
      });
      if (res.ok) {
        const data = await res.json();
        setAsistenciaLocal(data || []);
        return data || [];
      }
    } catch(e) {
      console.warn("Error recargando asistencia:", e);
    }
    return asistenciaLocal;
  };

  // Si no hay eventos pasados, intentar cargar desde GCal directamente
  useEffect(() => {
    if (eventos && eventos.length > 0) {
      setGcalEventos(eventos);
    } else {
      setGcalLoading(true);
      fetchGoogleCalendarEvents().then(ev => {
        setGcalEventos(ev || []);
        setGcalLoading(false);
      });
    }
  }, [eventos]);

  // Incluir también eventos pasados: cargar con timeMin más atrás
  useEffect(() => {
    setGcalLoading(true);
    const calId = encodeURIComponent(GCAL_CALENDAR_ID);
    const threeMonthsAgo = new Date();
    threeMonthsAgo.setMonth(threeMonthsAgo.getMonth() - 3);
    const url = `https://www.googleapis.com/calendar/v3/calendars/${calId}/events?key=${GCAL_API_KEY}&timeMin=${threeMonthsAgo.toISOString()}&maxResults=50&singleEvents=true&orderBy=startTime`;
    fetch(url).then(r => r.json()).then(data => {
      const items = (data.items || []).map((item) => {
        const start = item.start?.dateTime || item.start?.date || "";
        const isDateTime = !!item.start?.dateTime;
        const fecha = start.split("T")[0];
        const hora = isDateTime
          ? new Date(item.start.dateTime).toLocaleTimeString("es-CL", { hour: "2-digit", minute: "2-digit", hour12: false })
          : "";
        const titulo = item.summary || "Sin título";
        const tl = titulo.toLowerCase();
        const tipo = tl.includes("ensayo") ? "ensayo" : tl.includes("misa") || tl.includes("vigilia") || tl.includes("corpus") || tl.includes("pentecost") || tl.includes("pascua") ? "misa" : "evento";
        return { id: item.id, titulo, fecha, hora, tipo, lugar: item.location || "", descripcion: item.description || "" };
      });
      setGcalEventos(items);
      setGcalLoading(false);
    }).catch(() => setGcalLoading(false));
  }, []);

  const eventosOrdenados = [...gcalEventos].sort((a, b) => new Date(b.fecha) - new Date(a.fecha));

  // Al cambiar evento, recargar asistencia fresca desde Supabase antes de inicializar registros
  useEffect(() => {
    if (!eventoId) return;
    setSaved(false);
    recargarAsistencia().then(asisActual => {
      const init = {};
      members.forEach(m => {
        const reg = asisActual.find(a => a.evento_id === eventoId && a.member_id === m.id);
        if (reg) {
          init[m.id] = reg.estado;
        } else {
          init[m.id] = m.es_nuevo ? "nuevo" : "ausente";
        }
      });
      setRegistros(init);
    });
  }, [eventoId, members]);

  const marcarTodos = (estado) => {
    const nuevo = {};
    members.forEach(m => { nuevo[m.id] = estado; });
    setRegistros(nuevo);
  };

  const guardar = async () => {
    if (!eventoId) return;
    setSaving(true);
    const token = _authToken || SUPABASE_KEY;
    try {
      // Siempre obtener la asistencia más reciente de Supabase antes de guardar
      const asisActual = await recargarAsistencia();
      for (const m of members) {
        const estado = registros[m.id];
        if (!estado) continue;
        const existe = asisActual.find(a => a.evento_id === eventoId && a.member_id === m.id);
        if (existe) {
          const r = await fetch(`${SUPABASE_URL}/rest/v1/asistencia?id=eq.${existe.id}`, {
            method: "PATCH",
            headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${token}`, "Content-Type": "application/json" },
            body: JSON.stringify({ estado }),
          });
          if (!r.ok) { const e = await r.text(); console.error("Error PATCH asistencia:", r.status, e); }
        } else {
          const r = await fetch(`${SUPABASE_URL}/rest/v1/asistencia`, {
            method: "POST",
            headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${token}`, "Content-Type": "application/json", Prefer: "return=minimal" },
            body: JSON.stringify({ evento_id: eventoId, member_id: m.id, estado }),
          });
          if (!r.ok) { const e = await r.text(); console.error("Error POST asistencia:", r.status, e); }
        }
      }
      // Recargar localmente después de guardar
      await recargarAsistencia();
      setSaved(true);
      onReload();
    } catch(err) {
      console.error("Error guardando asistencia:", err);
      alert("Error al guardar: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const presentes = Object.values(registros).filter(e => e === "presente").length;
  const justificados = Object.values(registros).filter(e => e === "justificado").length;
  const ausentes = Object.values(registros).filter(e => e === "ausente").length;
  const excluidos = Object.values(registros).filter(e => e === "excluido").length;
  const nuevosCount = Object.values(registros).filter(e => e === "nuevo").length;

  return (
    <div>
    <div style={{ marginBottom: 16 }}>
        <label style={{ display: "block", fontSize: 13, fontWeight: 600, color: C.dark, marginBottom: 6 }}>Selecciona un evento del calendario</label>
        {gcalLoading ? (
          <div style={{ padding: "10px 12px", borderRadius: 12, border: `1px solid ${C.border}`, fontSize: 13, color: C.gray, background: C.bg }}>⏳ Cargando eventos de Google Calendar...</div>
        ) : (
        <select value={eventoId} onChange={e => setEventoId(e.target.value)} style={{ width: "100%", padding: "10px 12px", borderRadius: 12, border: `1px solid ${C.border}`, fontSize: 14, color: C.dark, background: "white" }}>
          <option value="">— Selecciona un evento —</option>
          {eventosOrdenados.map(e => {
            const tipoEmoji = e.tipo === "ensayo" ? "🎵" : e.tipo === "misa" ? "⛪" : "📅";
            const horaStr = e.hora ? ` ${e.hora}` : "";
            return (
              <option key={e.id} value={e.id}>
                {tipoEmoji} {new Date(e.fecha + "T00:00:00").toLocaleDateString("es-CL", { day: "numeric", month: "long", year: "numeric" })}{horaStr} · {e.titulo}
              </option>
            );
          })}
        </select>
        )}
      </div>

      {eventoId && (
        <>
          {/* Resumen */}
          <div style={{ display: "flex", gap: 10, marginBottom: 14, flexWrap: "wrap" }}>
            <div style={{ flex: 1, minWidth: 80, background: C.primaryLight, borderRadius: 12, padding: "10px 14px", textAlign: "center" }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: C.primary }}>{presentes}</div>
              <div style={{ fontSize: 11, color: C.primary }}>Presentes</div>
            </div>
            <div style={{ flex: 1, minWidth: 80, background: "#fef3c7", borderRadius: 12, padding: "10px 14px", textAlign: "center" }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: "#f59e0b" }}>{justificados}</div>
              <div style={{ fontSize: 11, color: "#f59e0b" }}>Justificados</div>
            </div>
            <div style={{ flex: 1, minWidth: 80, background: "#fee2e2", borderRadius: 12, padding: "10px 14px", textAlign: "center" }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: "#ef4444" }}>{ausentes}</div>
              <div style={{ fontSize: 11, color: "#ef4444" }}>Ausentes</div>
            </div>
            <div style={{ flex: 1, minWidth: 80, background: "#ede9fe", borderRadius: 12, padding: "10px 14px", textAlign: "center" }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: "#8b5cf6" }}>{excluidos}</div>
              <div style={{ fontSize: 11, color: "#8b5cf6" }}>🔵 Excluidos</div>
            </div>
            <div style={{ flex: 1, minWidth: 80, background: "#cffafe", borderRadius: 12, padding: "10px 14px", textAlign: "center" }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: "#06b6d4" }}>{nuevosCount}</div>
              <div style={{ fontSize: 11, color: "#06b6d4" }}>🆕 Nuevos</div>
            </div>
          </div>

          {/* Botones marcar todos */}
          <div style={{ display: "flex", gap: 8, marginBottom: 14, flexWrap: "wrap" }}>
            <button onClick={() => marcarTodos("presente")} style={{ padding: "6px 14px", borderRadius: 10, border: `1px solid ${C.primary}`, background: C.primaryLight, color: C.primary, fontSize: 12, fontWeight: 600, cursor: "pointer" }}>✅ Todos presentes</button>
            <button onClick={() => marcarTodos("ausente")} style={{ padding: "6px 14px", borderRadius: 10, border: "1px solid #ef4444", background: "#fee2e2", color: "#ef4444", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>❌ Todos ausentes</button>
            <button onClick={() => marcarTodos("excluido")} style={{ padding: "6px 14px", borderRadius: 10, border: "1px solid #8b5cf6", background: "#ede9fe", color: "#8b5cf6", fontSize: 12, fontWeight: 600, cursor: "pointer" }}>🔵 Excluir todos</button>
          </div>

          {/* Lista de integrantes */}
          <Card style={{ padding: 0, overflow: "hidden", marginBottom: 16 }}>
            {members.map((m, i) => {
              const cc = CUERDAS[m.cuerda] || C.primary;
              const estado = registros[m.id] || "ausente";
              return (
                <div key={m.id} style={{ display: "flex", alignItems: "center", gap: 12, padding: "12px 16px", borderTop: i > 0 ? `1px solid ${C.border}` : "none", background: i % 2 === 0 ? "#fff" : C.bg }}>
                  <div style={{ width: 36, height: 36, borderRadius: "50%", background: cc, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 13, fontWeight: 700, flexShrink: 0, overflow: "hidden" }}>
                    {m.foto_url ? <img src={m.foto_url} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : ini(m.nombre || "?")}
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: 600, color: C.dark, fontSize: 13 }}>{m.nombre}</div>
                    <div style={{ fontSize: 11, color: cc }}>{rolFullLabel(m)}</div>
                  </div>
                  <div style={{ display: "flex", gap: 6 }}>
                    {["presente", "justificado", "ausente", "excluido", "nuevo"].map(op => {
                      const labels = { presente: "✅", justificado: "🟡", ausente: "❌", excluido: "🔵", nuevo: "🆕" };
                      const colors = { presente: C.primary, justificado: "#f59e0b", ausente: "#ef4444", excluido: "#8b5cf6", nuevo: "#06b6d4" };
                      const tooltips = { presente: "Presente", justificado: "Justificado", ausente: "Ausente", excluido: "Excluido (no aplica)", nuevo: "Integrante nuevo" };
                      const activo = estado === op;
                      return (
                        <button key={op} onClick={() => setRegistros(r => ({ ...r, [m.id]: op }))}
                          title={tooltips[op]}
                          style={{ width: 34, height: 34, borderRadius: 10, border: activo ? `2px solid ${colors[op]}` : `1px solid ${C.border}`, background: activo ? colors[op] + "20" : "white", cursor: "pointer", fontSize: 16, display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.15s" }}>
                          {labels[op]}
                        </button>
                      );
                    })}
                  </div>
                </div>
              );
            })}
          </Card>

          <button onClick={guardar} disabled={saving} style={{ width: "100%", padding: "12px", borderRadius: 12, border: "none", background: saved ? "#10b981" : C.primary, color: "white", fontSize: 14, fontWeight: 700, cursor: saving ? "not-allowed" : "pointer" }}>
            {saving ? "Guardando..." : saved ? "✅ Guardado correctamente" : "Guardar asistencia"}
          </button>
        </>
      )}
    </div>
  );
}

// ══════════════════════════════════════════
//  ADMIN CUENTAS
// ══════════════════════════════════════════
function AdminCuentas({ members, onReload }) {
  const [selectedId, setSelectedId] = useState(null);
  const [newPass, setNewPass] = useState("");
  const [newPass2, setNewPass2] = useState("");
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState("");
  const [msgType, setMsgType] = useState("ok"); // "ok" | "error"
  const [confirmBaja, setConfirmBaja] = useState(null); // member id

  const selected = members.find(m => m.id === selectedId);

  const flash = (text, type = "ok") => {
    setMsg(text); setMsgType(type);
    setTimeout(() => setMsg(""), 3500);
  };

  // Cambiar contraseña usando service_role (Admin API)
  const cambiarPassword = async () => {
    if (!selectedId) return;
    if (newPass.length < 6) { flash("La contraseña debe tener al menos 6 caracteres.", "error"); return; }
    if (newPass !== newPass2) { flash("Las contraseñas no coinciden.", "error"); return; }
    setSaving(true);
    try {
      // Buscar el auth_user_id del integrante
      const member = members.find(m => m.id === selectedId);
      if (!member?.auth_id) throw new Error("No se encontró el auth_id del integrante.");
      // Usar Admin API de Supabase con service_role
      const res = await fetch(`${SUPABASE_URL}/auth/v1/admin/users/${member.auth_id}`, {
        method: "PUT",
        headers: {
          apikey: SUPABASE_SERVICE_KEY,
          Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ password: newPass }),
      });
      if (!res.ok) {
        const d = await res.json();
        throw new Error(d.msg || d.message || "Error al cambiar contraseña");
      }
      flash("✅ Contraseña cambiada correctamente.");
      setNewPass(""); setNewPass2("");
    } catch (e) {
      flash(e.message, "error");
    }
    setSaving(false);
  };

  // Dar de baja: deshabilitar cuenta en Supabase Auth
  const darDeBaja = async (memberId) => {
    const member = members.find(m => m.id === memberId);
    if (!member) return;
    setSaving(true);
    try {
      // Deshabilitar en auth
      const res = await fetch(`${SUPABASE_URL}/auth/v1/admin/users/${member.auth_id}`, {
        method: "PUT",
        headers: {
          apikey: SUPABASE_SERVICE_KEY,
          Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ ban_duration: "876000h" }), // ~100 años = baja permanente
      });
      if (!res.ok) {
        const d = await res.json();
        throw new Error(d.msg || d.message || "Error al dar de baja");
      }
      // Marcar en tabla integrantes
      await fetch(`${SUPABASE_URL}/rest/v1/integrantes?id=eq.${memberId}`, {
        method: "PATCH",
        headers: {
          apikey: SUPABASE_KEY,
          Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ activo: false }),
      });
      flash("✅ Cuenta dada de baja correctamente.");
      setConfirmBaja(null);
      if (selectedId === memberId) setSelectedId(null);
      onReload();
    } catch (e) {
      flash(e.message, "error");
    }
    setSaving(false);
  };

  // Reactivar cuenta
  const reactivar = async (memberId) => {
    const member = members.find(m => m.id === memberId);
    if (!member) return;
    setSaving(true);
    try {
      const res = await fetch(`${SUPABASE_URL}/auth/v1/admin/users/${member.auth_id}`, {
        method: "PUT",
        headers: {
          apikey: SUPABASE_SERVICE_KEY,
          Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ ban_duration: "none" }),
      });
      if (!res.ok) {
        const d = await res.json();
        throw new Error(d.msg || d.message || "Error al reactivar");
      }
      await fetch(`${SUPABASE_URL}/rest/v1/integrantes?id=eq.${memberId}`, {
        method: "PATCH",
        headers: {
          apikey: SUPABASE_KEY,
          Authorization: `Bearer ${SUPABASE_SERVICE_KEY}`,
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ activo: true }),
      });
      flash("✅ Cuenta reactivada correctamente.");
      onReload();
    } catch (e) {
      flash(e.message, "error");
    }
    setSaving(false);
  };

  return (
    <div>
      <div style={{ fontSize: 13, color: C.gray, marginBottom: 16, lineHeight: 1.6 }}>
        Gestiona las cuentas de los integrantes. Puedes cambiar contraseñas y dar de baja cuentas.
      </div>

      {msg && (
        <div style={{ padding: "10px 14px", borderRadius: 12, marginBottom: 14, fontSize: 13, fontWeight: 600,
          background: msgType === "ok" ? "#d1fae5" : "#fee2e2",
          color: msgType === "ok" ? "#065f46" : "#991b1b",
          border: `1px solid ${msgType === "ok" ? "#6ee7b7" : "#fca5a5"}` }}>
          {msg}
        </div>
      )}

      {/* Lista de integrantes */}
      <div style={{ marginBottom: 20 }}>
        <label style={{ fontSize: 13, fontWeight: 600, color: C.dark, display: "block", marginBottom: 8 }}>
          Selecciona un integrante
        </label>
        <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 320, overflowY: "auto", border: `1px solid ${C.border}`, borderRadius: 14, padding: 8 }}>
          {members.map(m => {
            const cc = CUERDAS[m.cuerda] || C.primary;
            const inactivo = m.activo === false;
            const sel = selectedId === m.id;
            return (
              <div key={m.id} onClick={() => { setSelectedId(sel ? null : m.id); setNewPass(""); setNewPass2(""); setMsg(""); }}
                style={{ display: "flex", alignItems: "center", gap: 10, padding: "10px 12px", borderRadius: 12, cursor: "pointer",
                  background: sel ? C.primary + "15" : "transparent",
                  border: sel ? `1.5px solid ${C.primary}` : "1.5px solid transparent",
                  opacity: inactivo ? 0.5 : 1 }}>
                <div style={{ width: 36, height: 36, borderRadius: "50%", background: cc, display: "flex", alignItems: "center", justifyContent: "center", color: "white", fontSize: 13, fontWeight: 700, flexShrink: 0, overflow: "hidden" }}>
                  {m.foto_url ? <img src={m.foto_url} alt="" style={{ width: "100%", height: "100%", objectFit: "cover" }} /> : ini(m.nombre || "?")}
                </div>
                <div style={{ flex: 1 }}>
                  <div style={{ fontWeight: 600, color: C.dark, fontSize: 13 }}>{m.nombre} {inactivo && <span style={{ fontSize: 10, color: "#ef4444", fontWeight: 700 }}>BAJA</span>}</div>
                  <div style={{ fontSize: 11, color: cc }}>{rolFullLabel(m)}</div>
                </div>
                {inactivo ? (
                  <button onClick={e => { e.stopPropagation(); reactivar(m.id); }} disabled={saving}
                    style={{ padding: "4px 10px", borderRadius: 10, border: `1px solid ${C.primary}`, background: C.primaryLight, color: C.primary, fontSize: 11, fontWeight: 600, cursor: "pointer" }}>
                    Reactivar
                  </button>
                ) : (
                  confirmBaja === m.id ? (
                    <div style={{ display: "flex", gap: 4 }} onClick={e => e.stopPropagation()}>
                      <button onClick={() => darDeBaja(m.id)} disabled={saving}
                        style={{ padding: "4px 10px", borderRadius: 10, border: "1px solid #ef4444", background: "#fee2e2", color: "#ef4444", fontSize: 11, fontWeight: 700, cursor: "pointer" }}>
                        Confirmar baja
                      </button>
                      <button onClick={() => setConfirmBaja(null)}
                        style={{ padding: "4px 8px", borderRadius: 10, border: `1px solid ${C.border}`, background: "white", color: C.gray, fontSize: 11, cursor: "pointer" }}>
                        Cancelar
                      </button>
                    </div>
                  ) : (
                    <button onClick={e => { e.stopPropagation(); setConfirmBaja(m.id); }}
                      style={{ padding: "4px 10px", borderRadius: 10, border: "1px solid #ef4444", background: "#fff0f0", color: "#ef4444", fontSize: 11, fontWeight: 600, cursor: "pointer" }}>
                      Dar de baja
                    </button>
                  )
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Panel de cambio de contraseña */}
      {selected && selected.activo !== false && (
        <div style={{ background: C.bg, borderRadius: 14, padding: 16, border: `1px solid ${C.border}` }}>
          <div style={{ fontWeight: 700, color: C.dark, fontSize: 14, marginBottom: 12 }}>
            🔑 Cambiar contraseña — {selected.nombre}
          </div>
          <div style={{ marginBottom: 10 }}>
            <label style={{ fontSize: 12, fontWeight: 600, color: C.gray, display: "block", marginBottom: 4 }}>Nueva contraseña</label>
            <input type="password" value={newPass} onChange={e => setNewPass(e.target.value)}
              placeholder="Mínimo 6 caracteres" minLength={6}
              style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: `1px solid ${C.border}`, fontSize: 14, boxSizing: "border-box" }} />
          </div>
          <div style={{ marginBottom: 14 }}>
            <label style={{ fontSize: 12, fontWeight: 600, color: C.gray, display: "block", marginBottom: 4 }}>Repetir contraseña</label>
            <input type="password" value={newPass2} onChange={e => setNewPass2(e.target.value)}
              placeholder="Repite la contraseña" minLength={6}
              style={{ width: "100%", padding: "10px 12px", borderRadius: 10, border: `1px solid ${C.border}`, fontSize: 14, boxSizing: "border-box" }} />
          </div>
          <div style={{ fontSize: 11, color: C.gray, marginBottom: 12, background: "#fef3c7", padding: "8px 12px", borderRadius: 10, border: "1px solid #fde68a" }}>
            💡 Asigna una contraseña temporal y comunícasela al integrante para que luego la cambie desde su perfil.
          </div>
          <button onClick={cambiarPassword} disabled={saving || !newPass || !newPass2}
            style={{ width: "100%", padding: "11px", borderRadius: 12, border: "none",
              background: saving || !newPass || !newPass2 ? "#e5e7eb" : C.primary,
              color: saving || !newPass || !newPass2 ? C.gray : "white",
              fontSize: 14, fontWeight: 700, cursor: saving || !newPass || !newPass2 ? "not-allowed" : "pointer" }}>
            {saving ? "Guardando..." : "Cambiar contraseña"}
          </button>
        </div>
      )}
    </div>
  );
}

