// ═══════════════════════════════════════════════════════════════
//  RECONÓCEME — Widget para el Dashboard (full-width destacado)
// ═══════════════════════════════════════════════════════════════
// ── Reacciones por reconocimiento ──────────────────────────────
const REACCIONES_DEF = [
  { tipo: "like",     emoji: "🤜", label: "Dale!" },
  { tipo: "corazon",  emoji: "❤️", label: "Me encanta" },
  { tipo: "estrella", emoji: "⭐", label: "Destacado" },
];

function ReaccionesBar({ recoId, userId }) {
  const [counts, setCounts]   = useState({ like: 0, corazon: 0, estrella: 0 });
  const [mias,   setMias]     = useState(new Set());
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (!recoId) return;
    fetch(
      `${SUPABASE_URL}/rest/v1/reco_reacciones?reco_id=eq.${recoId}&select=tipo,user_id`,
      { headers: { apikey: SUPABASE_SERVICE_KEY, Authorization: `Bearer ${SUPABASE_SERVICE_KEY}` } }
    )
      .then(r => r.ok ? r.json() : [])
      .then(rows => {
        const c = { like: 0, corazon: 0, estrella: 0 };
        const m = new Set();
        rows.forEach(row => {
          c[row.tipo] = (c[row.tipo] || 0) + 1;
          if (row.user_id === userId) m.add(row.tipo);
        });
        setCounts(c);
        setMias(m);
      })
      .catch(() => {});
  }, [recoId, userId]);

  async function toggleReaccion(tipo) {
    if (!userId || !recoId || loading) return;
    setLoading(true);
    const yaTengo = mias.has(tipo);
    const tipoAnterior = [...mias].find(t => t !== tipo) || null;
    setCounts(prev => {
      const next = { ...prev, [tipo]: Math.max(0, prev[tipo] + (yaTengo ? -1 : 1)) };
      if (!yaTengo && tipoAnterior) next[tipoAnterior] = Math.max(0, prev[tipoAnterior] - 1);
      return next;
    });
    setMias(() => yaTengo ? new Set() : new Set([tipo]));
    const SK = SUPABASE_SERVICE_KEY;
    const hdrs = { apikey: SK, Authorization: `Bearer ${SK}` };
    try {
      if (!yaTengo && tipoAnterior) {
        await fetch(
          `${SUPABASE_URL}/rest/v1/reco_reacciones?reco_id=eq.${recoId}&user_id=eq.${userId}&tipo=eq.${tipoAnterior}`,
          { method: "DELETE", headers: hdrs }
        );
      }
      if (yaTengo) {
        await fetch(
          `${SUPABASE_URL}/rest/v1/reco_reacciones?reco_id=eq.${recoId}&user_id=eq.${userId}&tipo=eq.${tipo}`,
          { method: "DELETE", headers: hdrs }
        );
      } else {
        const res = await fetch(`${SUPABASE_URL}/rest/v1/reco_reacciones`, {
          method: "POST",
          headers: { ...hdrs, "Content-Type": "application/json", Prefer: "resolution=ignore-duplicates,return=minimal" },
          body: JSON.stringify({ reco_id: recoId, user_id: userId, tipo }),
        });
        if (!res.ok) {
          const err = await res.text();
          console.error("Reacción error:", res.status, err);
          if (res.status !== 409) throw new Error(err); // 409 = ya existe, no revertir
        }
      }
    } catch(e) {
      console.error("toggleReaccion catch:", e);
      setCounts(prev => {
        const next = { ...prev, [tipo]: Math.max(0, prev[tipo] + (yaTengo ? 1 : -1)) };
        if (!yaTengo && tipoAnterior) next[tipoAnterior] = Math.max(0, prev[tipoAnterior] + 1);
        return next;
      });
      setMias(prev => {
        const s = new Set(prev);
        yaTengo ? s.add(tipo) : s.delete(tipo);
        if (!yaTengo && tipoAnterior) s.add(tipoAnterior);
        return s;
      });
    }
    setLoading(false);
  }

  return (
    <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
      {REACCIONES_DEF.map(({ tipo, emoji, label }) => {
        const active = mias.has(tipo);
        const count  = counts[tipo] || 0;
        return (
          <button
            key={tipo}
            title={userId ? label : "Inicia sesión para reaccionar"}
            onClick={(e) => { e.stopPropagation(); toggleReaccion(tipo); }}
            style={{
              display: "flex", alignItems: "center", gap: 5,
              padding: "5px 12px", borderRadius: 24,
              border: active
                ? tipo === "like"     ? "1px solid rgba(99,102,241,0.5)"
                : tipo === "corazon"  ? "1px solid rgba(239,68,68,0.5)"
                :                       "1px solid rgba(251,191,36,0.5)"
                : "1px solid rgba(0,0,0,0.10)",
              background: active
                ? tipo === "like"     ? "rgba(99,102,241,0.10)"
                : tipo === "corazon"  ? "rgba(239,68,68,0.10)"
                :                       "rgba(251,191,36,0.10)"
                : "rgba(0,0,0,0.03)",
              cursor: userId ? "pointer" : "default",
              fontSize: 13, lineHeight: 1,
              transition: "all 0.18s",
              transform: active ? "scale(1.10)" : "scale(1)",
              boxShadow: active ? "0 2px 8px rgba(0,0,0,0.10)" : "none",
            }}
          >
            <span style={{ fontSize: 16, lineHeight:1 }}>{emoji}</span>
            {count > 0 && (
              <span style={{
                fontSize: 11, fontWeight: 700, minWidth: 12,
                color: active
                  ? tipo === "like"    ? "#4f46e5"
                  : tipo === "corazon" ? "#dc2626"
                  :                      "#d97706"
                  : "#9ca3af",
              }}>
                {count}
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}

